import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";

export default function MusicScanner() {
  const [song, setSong] = useState(null);

  const handleScan = (result) => {
    if (!result?.[0]?.rawValue) return;

    const text = result[0].rawValue;

    // Format QR:
    // SONG:Shape of You;ARTIST:Ed Sheeran;FILE:shape-of-you.mp3
    const parts = Object.fromEntries(
      text.split(";").map((p) => p.split(":"))
    );

    setSong({
      title: parts.SONG || "Nieznany tytuł",
      artist: parts.ARTIST || "Nieznany wykonawca",
      file: parts.FILE || null,
    });
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>🎵 QR Music Scanner</h1>

      {!song && (
        <>
          <p>Zeskanuj kod QR z informacjami o piosence.</p>
          <Scanner onScan={handleScan} />
        </>
      )}

      {song && (
        <div style={{ marginTop: 20 }}>
          <h2>{song.title}</h2>
          <h3>{song.artist}</h3>

          {song.file ? (
            <audio
              controls
              src={`/audio/${song.file}`}
              style={{ width: "100%" }}
            />
          ) : (
            <p>Brak pliku audio.</p>
          )}

          <button
            onClick={() => setSong(null)}
            style={{
              marginTop: 20,
              padding: "10px 20px",
              fontSize: 16,
            }}
          >
            Skanuj kolejną piosenkę
          </button>
        </div>
      )}
    </div>
  );
}
